module sr_flip_flop (  
    input wire S,  
    input wire R,  
    input wire CLK,  
    output reg Q  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin  
        if (R)  
            Q <= 0;  
        else if (S)  
            Q <= 1;  
    end  
endmodule
